<span class="line"><span style="color:#CDD6F4;">    lines</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Vec</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">Line</span><span style="color:#89DCEB;">&lt;</span><span style="color:#9399B2;">&#39;</span><span style="color:#89B4FA;font-style:italic;">static</span><span style="color:#89DCEB;">&gt;&gt;</span><span style="color:#9399B2;">,</span></span>
